-- Tempo Bodyweight Squat (tempo-bodyweight-squat) [insert]
UPDATE coaching.exercise SET
  name = 'Tempo Bodyweight Squat',
  description = 'Tempo Bodyweight Squat is a tempo/eccentric bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.',
  card_summary = 'Slow-tempo squat that turns air-squat leverage into a real strength stimulus through time under tension, bracing, depth ownership, and repeatable knee/hip alignment. Strength is the primary score; explosiveness is delivery-dependent, not the main intent.',
  coach_language = 'Primary subrole: squat / knee / dominant / strength. Score Strength high. Add Explosiveness only as a small secondary score when the coach prescribes crisp concentric intent, low fatigue, and adequate rest; do not treat this as a plyometric, burpee, jump, or conditioning station.',
  athlete_language = 'Set the position first, move with control, and finish every rep like you could repeat it cleanly. Strong and sharp beats rushed and sloppy.',
  movement_family = 'Squat / Knee-Dominant Bodyweight Strength',
  primary_phase_key = 'capacity',
  phase_subrole = 'squat_knee_dominant_strength',
  primary_order_slot = 'bodyweight_tempo_bodyweight_squat_strength',
  default_sets = 3,
  default_reps = 8,
  default_work_seconds = 40,
  default_rest_seconds = 90,
  est_seconds_per_set = 130,
  movement_requirements = '{"primary_joint_actions":["hip_flexion","knee_flexion","ankle_dorsiflexion","hip_extension","knee_extension"],"primary_tissues":["quadriceps","glutes","adductors","calves"],"breathing_demand":"braced_controlled","balance_demand":"stable_to_moderate","coordination_demand":"moderate","impact_level":0,"loading_strategy":"bodyweight_relative_strength","excluded_delivery":["burpee_conditioning","jump_based_plyometrics","fatigue_chase"]}'::jsonb,
  coaching_execution = '{"movement_description":"Tempo Bodyweight Squat is a tempo/eccentric bodyweight strength exercise. Use leverage, range, tempo, pause, and rest to create force production instead of conditioning fatigue.","setup":["Clear a non-slip training space and choose a variation the athlete can control without pain.","Set the starting body line before the first rep: brace, align the target joints, and keep the face/neck relaxed.","Use a stance and range of motion that the athlete can repeat with knee, hip, ankle, and trunk control."],"execution_steps":["Start each repetition from a still, organized position.","Lower slowly through the prescribed range; do not drop, bounce, or rush the eccentric.","Drive through the concentric portion with strong intent while keeping the same body line and joint path.","Reset at the top or start position before the next rep so every rep looks repeatable."],"coach_cues":["Own the bottom.","Drive without jumping.","Knee tracks over toes.","Ribs stacked over pelvis."],"athlete_cues":["Own the setup.","Strong but quiet reps.","Stop before shape breaks."],"breathing_cues":["Inhale before the hard part when needed.","Brace without panic breathing.","Exhale through the sticking point or after the rep without collapsing."],"common_faults":["Chasing fatigue or rep count instead of strength-quality reps.","Knees collapse inward or heels lift without control.","Bouncing out of the bottom instead of producing force.","Torso position changes to survive the rep."],"quality_gate":["No pain or joint collapse.","Start and finish positions match the intended variation.","Final rep looks close to the first rep.","Coach would be comfortable progressing leverage, range, or volume next week."],"stop_signs":["Pain appears or changes the pattern.","Technique changes more than one rep in a row.","Breathing becomes dizziness, panic bracing, or uncontrolled breath holding.","Athlete uses momentum, swing, bounce, or impact to survive the set."]}'::jsonb,
  pairing_logic = '{"pairs_well_before":["Lower-skill accessory strength","Trunk or position-control work","Resilience work","Sustained Capacity only if movement quality remains safe"],"pairs_well_after":["General warm-up","Pattern-specific mobility access","Low-fatigue activation or technical rehearsal","True Output work if included earlier in the session"],"good_for_sessions":["bodyweight_strength","lower_body_strength"],"avoid_before":[],"avoid_after":[],"do_not_use_when":["Pain appears in the target pattern.","Athlete cannot control bodyweight safely in the chosen variation.","The session needs true max-speed or jump Output and this would create fatigue first.","The coach plans to use it as a burnout conditioning station."]}'::jsonb,
  media_library = '{"demo_video_sources":[],"coaching_articles":[],"clinical_or_sport_science_references":["Internal Vortex bodyweight strength demo recommended","Vortex Exercise Card Authoring Guide: Capacity / strength sequencing rules","ACSM-style resistance training technique and progression guidance"],"internal_notes":["Film Tempo Bodyweight Squat from front/side where useful.","Keep Strength as the primary tenet.","Explosiveness score is optional and delivery-dependent; do not program as plyometrics or conditioning."]}'::jsonb,
  updated_at = now()
WHERE slug = 'tempo-bodyweight-squat';

UPDATE coaching.exercise_phase_profile p SET
  role = 'primary',
  order_slot = 'bodyweight_tempo_bodyweight_squat_strength',
  order_index = pos.order_index,
  fit_weight = 5,
  freshness_required = FALSE,
  fatigue_sensitivity = 3,
  fatigue_cost = 3,
  technical_complexity = 2,
  impact_level = 0,
  intensity_ceiling = 'moderate',
  notes = ''
FROM coaching.exercise e
JOIN coaching.session_phase sp ON sp.key = 'capacity'
JOIN coaching.phase_order_slot pos ON pos.key = 'bodyweight_tempo_bodyweight_squat_strength' AND pos.phase_id = sp.id
WHERE p.exercise_id = e.id AND p.phase_id = sp.id AND e.slug = 'tempo-bodyweight-squat';

UPDATE coaching.exercise_dosage_profile d SET
  volume_unit = 'reps',
  default_sets = 3,
  default_reps = 8,
  default_distance = NULL::integer,
  default_work_seconds = 40,
  default_rest_seconds = 90,
  est_seconds_per_set = 130,
  default_rpe_min = 6,
  default_rpe_max = 8,
  session_volume_min = NULL,
  session_volume_max = NULL
FROM coaching.exercise e
WHERE d.exercise_id = e.id AND d.profile_name = 'Default' AND e.slug = 'tempo-bodyweight-squat';

UPDATE coaching.exercise_regimen_rule r SET
  can_be_daily = FALSE,
  weekly_max_frequency = 3,
  minimum_hours_between_hard_exposures = 24,
  counts_as_high_intensity = FALSE,
  counts_as_high_impact = FALSE,
  counts_as_neural = TRUE,
  counts_as_tissue_stress = TRUE,
  counts_as_conditioning = FALSE
FROM coaching.exercise e
WHERE r.exercise_id = e.id AND e.slug = 'tempo-bodyweight-squat';

UPDATE coaching.exercise_safety_profile s SET
  risk_level = 3,
  impact_level = 0,
  requires_spotting = FALSE,
  requires_coach_supervision = 'recommended',
  readiness_checks = ARRAY['Athlete can demonstrate the easier regression without pain.', 'Athlete can brace and breathe without dizziness.', 'Athlete can stop the set before technique deteriorates.', 'Training area and support equipment are stable and clear.']::text[],
  contraindications = ARRAY['Painful joint loading in the selected pattern.', 'Uncontrolled spine, shoulder, hip, knee, ankle, or wrist position.', 'No safe setup for the required support, bar, wall, rings, or floor space.']::text[],
  common_substitutions = ARRAY['Tempo Bodyweight Squat', 'Bodyweight Split Squat', 'Single-Leg Box Squat']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'tempo-bodyweight-squat';

