  readiness_checks = ARRAY['Athlete can demonstrate the easier regression without pain.', 'Athlete can brace and breathe without dizziness.', 'Athlete can stop the set before technique deteriorates.', 'Training area and support equipment are stable and clear.']::text[],
  contraindications = ARRAY['Painful joint loading in the selected pattern.', 'Uncontrolled spine, shoulder, hip, knee, ankle, or wrist position.', 'No safe setup for the required support, bar, wall, rings, or floor space.']::text[],
  common_substitutions = ARRAY['Ring Row', 'Inverted Row', 'Isometric Pull-Up Hold']::text[]
FROM coaching.exercise e
WHERE s.exercise_id = e.id AND e.slug = 'hanging-straight-leg-raise';

