USING coaching.exercise e
WHERE t.exercise_id = e.id
  AND e.slug IN ('tempo-bodyweight-squat', 'pause-bodyweight-squat', 'wall-sit', 'bodyweight-split-squat', 'rear-foot-elevated-split-squat', 'bodyweight-reverse-lunge', 'bodyweight-step-up', 'single-leg-box-squat', 'assisted-pistol-squat', 'pistol-squat', 'single-leg-glute-bridge', 'feet-elevated-hip-thrust', 'hamstring-walkout', 'sliding-hamstring-curl', 'assisted-nordic-hamstring-curl', 'reverse-nordic-curl', 'copenhagen-side-plank', 'single-leg-calf-raise', 'bent-knee-soleus-raise', 'tibialis-raise', 'push-up', 'tempo-push-up', 'feet-elevated-push-up', 'deficit-push-up', 'ring-push-up', 'archer-push-up', 'pseudo-planche-push-up', 'one-arm-push-up-progression', 'pike-push-up', 'box-pike-handstand-push-up', 'wall-handstand-push-up', 'chest-to-wall-handstand-hold', 'parallel-bar-dip', 'ring-dip', 'straight-bar-dip', 'inverted-row', 'feet-elevated-inverted-row', 'ring-row', 'pull-up', 'chin-up', 'eccentric-pull-up', 'isometric-pull-up-hold', 'archer-pull-up', 'tuck-front-lever-row', 'tuck-front-lever-hold', 'hollow-body-hold', 'rkc-plank', 'l-sit', 'hanging-knee-raise', 'hanging-straight-leg-raise')
