UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('tempo-bodyweight-squat', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
  ('pause-bodyweight-squat', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
  ('wall-sit', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
  ('bodyweight-split-squat', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
  ('rear-foot-elevated-split-squat', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
  ('bodyweight-reverse-lunge', 'Use the simplest leverage and shortest range that can be owned. Keep sets short, coach one cue at a time, and stop before fatigue changes alignment.', 'No default gender-specific adjustment. Scale by training age, body proportions, symptoms, recovery state, joint history, and current capacity rather than gender alone.'),
