-- Why-layer education
INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops tagged tenets and force/tissue capacity for bodyweight strength in the Capacity phase.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('tempo-bodyweight-squat', 'Tempo Bodyweight Squat uses bodyweight leverage as the resistance. The athlete must organize joints, trunk tension, and range while producing force against their own body mass, making the drill useful for relative strength without external loading.', 'Belongs in Capacity because the primary adaptation is strength, force production, tissue tolerance, and structural reserve. It can support later explosiveness when delivered with high intent, but it should not replace true Output plyometrics or speed work.', 'Use in the Capacity phase after Prepare & Access, Movement Intelligence, and any true Output work. Keep it before hard conditioning; pair with enough rest that strength-quality reps do not turn into a bodyweight burnout circuit.', 'The most common mistake is turning a bodyweight strength drill into a fast fatigue circuit because no external load is present. Keep tempo, leverage, range, rest, and rep quality aligned with strength first.', 'Scale by leverage, range of motion, tempo, pause length, assistance, support height, set length, and rest. Progress only when posture, pain-free range, and repeatable rep quality remain stable.'),
  ('pause-bodyweight-squat', 'Pause Bodyweight Squat uses bodyweight leverage as the resistance. The athlete must organize joints, trunk tension, and range while producing force against their own body mass, making the drill useful for relative strength without external loading.', 'Belongs in Capacity because the primary adaptation is strength, force production, tissue tolerance, and structural reserve. It can support later explosiveness when delivered with high intent, but it should not replace true Output plyometrics or speed work.', 'Use in the Capacity phase after Prepare & Access, Movement Intelligence, and any true Output work. Keep it before hard conditioning; pair with enough rest that strength-quality reps do not turn into a bodyweight burnout circuit.', 'The most common mistake is turning a bodyweight strength drill into a fast fatigue circuit because no external load is present. Keep tempo, leverage, range, rest, and rep quality aligned with strength first.', 'Scale by leverage, range of motion, tempo, pause length, assistance, support height, set length, and rest. Progress only when posture, pain-free range, and repeatable rep quality remain stable.'),
  ('wall-sit', 'Wall Sit uses bodyweight leverage as the resistance. The athlete must organize joints, trunk tension, and range while producing force against their own body mass, making the drill useful for relative strength without external loading.', 'Belongs in Capacity because the primary adaptation is strength, force production, tissue tolerance, and structural reserve. It can support later explosiveness when delivered with high intent, but it should not replace true Output plyometrics or speed work.', 'Use in the Capacity phase after Prepare & Access, Movement Intelligence, and any true Output work. Keep it before hard conditioning; pair with enough rest that strength-quality reps do not turn into a bodyweight burnout circuit.', 'The most common mistake is turning a bodyweight strength drill into a fast fatigue circuit because no external load is present. Keep tempo, leverage, range, rest, and rep quality aligned with strength first. Do not tag it as explosiveness just because the athlete is working hard; the card is mainly isometric/eccentric strength and tissue capacity.', 'Scale by leverage, range of motion, tempo, pause length, assistance, support height, set length, and rest. Progress only when posture, pain-free range, and repeatable rep quality remain stable.'),
  ('bodyweight-split-squat', 'Bodyweight Split Squat uses bodyweight leverage as the resistance. The athlete must organize joints, trunk tension, and range while producing force against their own body mass, making the drill useful for relative strength without external loading.', 'Belongs in Capacity because the primary adaptation is strength, force production, tissue tolerance, and structural reserve. It can support later explosiveness when delivered with high intent, but it should not replace true Output plyometrics or speed work.', 'Use in the Capacity phase after Prepare & Access, Movement Intelligence, and any true Output work. Keep it before hard conditioning; pair with enough rest that strength-quality reps do not turn into a bodyweight burnout circuit.', 'The most common mistake is turning a bodyweight strength drill into a fast fatigue circuit because no external load is present. Keep tempo, leverage, range, rest, and rep quality aligned with strength first.', 'Scale by leverage, range of motion, tempo, pause length, assistance, support height, set length, and rest. Progress only when posture, pain-free range, and repeatable rep quality remain stable.'),
